const cfg = $input.first().json;
const placeholders = [
  { key: 'baselineSkuId', value: cfg.baselineSkuId },
  { key: 'teamsTeamId', value: cfg.teamsTeamId },
  { key: 'teamsChannelId', value: cfg.teamsChannelId },
  { key: 'exemptionGroupId', value: cfg.exemptionGroupId }
];
const unfilled = placeholders.filter(p => typeof p.value === 'string' && p.value.startsWith('YOUR_'));
if (unfilled.length > 0) {
  throw new Error(`Config placeholders not replaced: ${unfilled.map(p => p.key).join(', ')}. Update Config node before activating.`);
}
return $input.all();

const result = $input.first().json;
if (result.error) {
  throw new Error(`Get Subscribed SKUs failed: ${result.error.message || JSON.stringify(result.error)}`);
}
const skus = result.value || [];
const premiumSkuPartNumbers = $('Set Configuration Parameters').item.json.premiumSkuPartNumbers || [];
const premiumSkuIds = skus
  .filter(s => premiumSkuPartNumbers.includes(s.skuPartNumber))
  .map(s => s.skuId);
if (premiumSkuIds.length === 0) {
  throw new Error(`No SKUs matched premiumSkuPartNumbers [${premiumSkuPartNumbers.join(', ')}]. Check your tenant subscriptions or Config values.`);
}
return [{ json: { premiumSkuIds } }];

let url = "https://graph.microsoft.com/v1.0/users?$filter=accountEnabled eq true and userType eq 'Member' and assignedLicenses/$count ne 0&$select=id,displayName,userPrincipalName,assignedLicenses,signInActivity,createdDateTime&$top=999&$count=true";
let allUsers = [];
let pageCount = 0;

while (url) {
  const response = await this.helpers.httpRequestWithAuthentication.call(
    this,
    'oAuth2Api',
    {
      method: 'GET',
      url,
      headers: { 'ConsistencyLevel': 'eventual' },
      returnFullResponse: false,
      json: true
    }
  );
  if (response.error) {
    throw new Error(`Get All Licensed Users page ${pageCount + 1} failed: ${response.error.message || JSON.stringify(response.error)}`);
  }
  allUsers = allUsers.concat(response.value || []);
  url = response['@odata.nextLink'] || null;
  pageCount++;
}

return [{ json: { value: allUsers, totalFetched: allUsers.length, pages: pageCount } }];

const users = $input.first().json.value || [];
const premiumSkuIds = $('Generate Premium SKU Map').item.json.premiumSkuIds || [];
const cutoffDate = new Date($('Set Configuration Parameters').item.json.cutoffDate);
const newHireWindowStart = new Date($('Set Configuration Parameters').item.json.newHireWindowStart);
const baselineSkuId = $('Set Configuration Parameters').item.json.baselineSkuId;

const exemptionData = $('Compile Exemption List').item.json.exemptions || [];
const exemptedUserIds = new Set(
  exemptionData.flatMap(page => page.value ? page.value.map(m => m.id) : [])
);

const inactiveUsers = users.filter(user => {
  if (!user.id) return false;
  if (exemptedUserIds.has(user.id)) return false;
  const hasPremium = (user.assignedLicenses || []).some(lic => premiumSkuIds.includes(lic.skuId));
  if (!hasPremium) return false;
  const signIn = user.signInActivity;
  if (!signIn || !signIn.lastSignInDateTime) {
    if (user.createdDateTime && new Date(user.createdDateTime) >= newHireWindowStart) return false;
    return true;
  }
  return new Date(signIn.lastSignInDateTime) < cutoffDate;
});

const downgradePlan = inactiveUsers.map(user => {
  const premiumLicensesToRemove = (user.assignedLicenses || [])
    .filter(lic => premiumSkuIds.includes(lic.skuId))
    .map(lic => lic.skuId);
  return {
    userId: user.id,
    displayName: user.displayName,
    userPrincipalName: user.userPrincipalName,
    lastSignIn: user.signInActivity?.lastSignInDateTime ?? 'Never',
    premiumLicensesToRemove,
    baselineSkuId
  };
});

return [{
  json: {
    downgradePlan,
    downgradeCount: downgradePlan.length,
    exemptionsFound: exemptedUserIds.size,
    totalScanned: users.length
  }
}];

