const isDryRun = !!$input.first().json.dryRun;

// Live path: $input.first().json is the Graph assignLicense response, which does not
// contain user fields. We source the original user object from the Wait (API Pacing)
// node, which holds it immediately before the Graph call.
// NOTE: If you rename 'Wait (API Pacing)', update this reference to match.
// Dry-run path: Dry Run Passthrough already carries all user fields on $input.
const user = isDryRun
  ? $input.first().json
  : $('Wait 0.5 Seconds').item.json;

return [{ json: { ...user, dryRun: isDryRun, status: 'success' } }];

