const isDryRun = $('Set Configuration Parameters').item.json.dryRunMode;
const raw = $input.first().json.processedUsers || [];

// aggregateAllItemData in n8n v3 wraps items as { json: {...} } in some versions.
// Normalise to plain objects regardless.
// Next Downgrade merges both Record Success and License Error Alert paths, so
// processedUsers contains Teams API response objects from the error path as well.
// These have no status field and are discarded by the filter below.
const allResults = raw.map(item => item.json ?? item);

const successes = allResults.filter(item => item.status === 'success');

const lines = successes.map((u, i) => {
  const tag = u.dryRun ? ' [DRY RUN]' : '';
  return `${i + 1}. ${u.displayName} (${u.userPrincipalName}) — Last Sign-In: ${u.lastSignIn}${tag}`;
}).join('\n');

return [{
  json: {
    summary: lines || 'No successful downgrades processed in this run.',
    count: successes.length,
    isDryRun: !!isDryRun,
    teamsTeamId: $('Set Configuration Parameters').item.json.teamsTeamId,
    teamsChannelId: $('Set Configuration Parameters').item.json.teamsChannelId
  }
}];

